    this.lastTrigger = 0;
  }

  /**
   * Checks if the cooldown has expired.
   * @returns {boolean} True if the cooldown has expired, false otherwise.
   */
  hasExpired() {
    return Date.now() - this.lastTrigger > this.duration;
  }

  /**
   * Triggers the cooldown and resets the timer.
