        _context = context;
    }

    public virtual async Task<T> FindAsync(object id)
    {
        return await _context.Set<T>().FindAsync(id);
    }

    public virtual async Task<T> FindAsync(Expression<Func<T, bool>> predicate)
    {
        return await _context.Set<T>().FirstOrDefaultAsync(predicate);
    }

    public virtual async Task<T> FindAsync(string field, object value)
    {
        // Use Expression<Func<T, bool>> to create a dynamic lambda expression
        var parameter = Expression.Parameter(typeof(T));
        var member = Expression.Property(parameter, field);
        var constant = Expression.Constant(value);
        var body = Expression.Equal(member, constant);
        var lambda = Expression.Lambda<Func<T, bool>>(body, parameter);

        return await _context.Set<T>().FirstOrDefaultAsync(lambda);
    }

